  # Special handling for language predicates
          if "language" in pred_vals:
              # integrate language info into the main clause
              for obj in pred_vals.pop("language"):
                  # store as a part that will be combined later
                  pred_vals.setdefault("_language_part", []).append(f"{obj} is spoken")
          if "officialLanguage" in pred_vals:
              for obj in pred_vals.pop("officialLanguage"):
                  pred_vals.setdefault("_language_part", []).append(f"The official language is {obj}")

          # Special handling for leaders (multiple possible)
          if "leader" in pred_vals:
              leaders = pred_vals.pop("leader")
              if len(leaders) == 1:
                  # phrase as "<leader> leads <subject>"
                  sentences.append(f"{leaders[0]} leads {subject}.")
              else:
                  sentences.append(
                      f"{', '.join(leaders[:-1])} and {leaders[-1]} lead {subject}."
                  )
